import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Box, Drawer, AppBar, Toolbar, List, Typography, Divider, IconButton,
  ListItem, ListItemButton, ListItemIcon, ListItemText, useMediaQuery
} from '@mui/material';
import {
  Menu as MenuIcon, Dashboard as DashboardIcon, Business as BusinessIcon,
  AttachMoney as MoneyIcon, Psychology as MindsetIcon, School as SchoolIcon,
  FitnessCenter as HealthIcon, CheckCircle as CheckIcon,
  Assessment as ReportsIcon, SmartToy as AIIcon, Logout as LogoutIcon,
  EmojiEvents as TrophyIcon
} from '@mui/icons-material';
import { useAuth } from '../context/AuthContext';
import { C } from '../theme';

const drawerWidth = 250;

const menuItems = [
  { text: 'Dashboard',   icon: <DashboardIcon />, path: '/' },
  { text: 'Business',    icon: <BusinessIcon />,  path: '/business' },
  { text: 'Best Idea',   icon: <TrophyIcon />,    path: '/best-idea' },
  { text: 'Financial',   icon: <MoneyIcon />,     path: '/financial' },
  { text: 'Mindset',     icon: <MindsetIcon />,   path: '/mindset' },
  { text: 'Learning',    icon: <SchoolIcon />,    path: '/learning' },
  { text: 'Health',      icon: <HealthIcon />,    path: '/health' },
  { text: 'Check-in',    icon: <CheckIcon />,     path: '/checkin' },
  { text: 'Reports',     icon: <ReportsIcon />,   path: '/reports' },
  { text: 'AI Advisor',  icon: <AIIcon />,        path: '/ai' },
];

// Floating cursor glow
function CursorGlow() {
  const ref = useRef(null);
  const target = useRef({ x: 0, y: 0 });
  const cur    = useRef({ x: 0, y: 0 });
  useEffect(() => {
    const onMove = e => { target.current = { x: e.clientX, y: e.clientY }; };
    window.addEventListener('mousemove', onMove);
    let raf;
    const tick = () => {
      cur.current.x += (target.current.x - cur.current.x) * 0.08;
      cur.current.y += (target.current.y - cur.current.y) * 0.08;
      if (ref.current) {
        ref.current.style.left = cur.current.x + 'px';
        ref.current.style.top  = cur.current.y + 'px';
      }
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => { window.removeEventListener('mousemove', onMove); cancelAnimationFrame(raf); };
  }, []);
  return (
    <Box ref={ref} sx={{
      position: 'fixed', pointerEvents: 'none', zIndex: 9998,
      width: 500, height: 500, borderRadius: '50%',
      background: `radial-gradient(circle, rgba(71,133,89,0.08) 0%, rgba(71,133,89,0.03) 40%, transparent 70%)`,
      transform: 'translate(-50%,-50%)',
    }} />
  );
}

// Animated background blobs matching the color scheme
function AnimatedBackground() {
  return (
    <Box sx={{
      position: 'fixed', inset: 0, zIndex: 0, pointerEvents: 'none', overflow: 'hidden',
    }}>
      {/* Large green blob top-right */}
      <Box sx={{
        position: 'absolute', top: '-10%', right: '-5%',
        width: 600, height: 600, borderRadius: '60% 40% 70% 30% / 50% 60% 40% 50%',
        background: `radial-gradient(ellipse, rgba(71,133,89,0.08) 0%, transparent 70%)`,
        animation: 'blob1 18s ease-in-out infinite',
        '@keyframes blob1': {
          '0%,100%': { borderRadius: '60% 40% 70% 30% / 50% 60% 40% 50%', transform: 'rotate(0deg) scale(1)' },
          '33%':     { borderRadius: '40% 60% 30% 70% / 60% 40% 60% 40%', transform: 'rotate(4deg) scale(1.05)' },
          '66%':     { borderRadius: '50% 50% 60% 40% / 40% 50% 50% 60%', transform: 'rotate(-3deg) scale(0.97)' },
        }
      }} />
      {/* Purple blob bottom-left */}
      <Box sx={{
        position: 'absolute', bottom: '-15%', left: '5%',
        width: 500, height: 500, borderRadius: '40% 60% 50% 50% / 60% 40% 60% 40%',
        background: `radial-gradient(ellipse, rgba(22,23,72,0.06) 0%, transparent 70%)`,
        animation: 'blob2 22s ease-in-out infinite',
        '@keyframes blob2': {
          '0%,100%': { borderRadius: '40% 60% 50% 50% / 60% 40% 60% 40%', transform: 'rotate(0deg) scale(1)' },
          '50%':     { borderRadius: '60% 40% 40% 60% / 40% 60% 40% 60%', transform: 'rotate(-5deg) scale(1.08)' },
        }
      }} />
      {/* Grey-blue accent mid */}
      <Box sx={{
        position: 'absolute', top: '40%', right: '20%',
        width: 300, height: 300, borderRadius: '50%',
        background: `radial-gradient(ellipse, rgba(79,95,118,0.05) 0%, transparent 70%)`,
        animation: 'blob3 14s ease-in-out infinite',
        '@keyframes blob3': {
          '0%,100%': { transform: 'scale(1) translateY(0)' },
          '50%':     { transform: 'scale(1.1) translateY(-20px)' },
        }
      }} />
      {/* Subtle pearl texture dots */}
      <Box sx={{
        position: 'absolute', inset: 0,
        backgroundImage: `radial-gradient(circle, rgba(71,133,89,0.04) 1px, transparent 1px)`,
        backgroundSize: '40px 40px',
      }} />
    </Box>
  );
}

// SW PG Logo
function Logo({ size = 42 }) {
  return (
    <Box sx={{
      width: size, height: size, borderRadius: Math.round(size * 0.22),
      background: C.greenGrad,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      boxShadow: `0 4px 14px rgba(71,133,89,0.45)`,
      position: 'relative', overflow: 'hidden', flexShrink: 0,
      '&::after': {
        content: '""', position: 'absolute',
        top: 0, left: 0, right: 0, height: '50%',
        background: 'rgba(255,255,255,0.12)',
        borderRadius: `${Math.round(size * 0.22)}px ${Math.round(size * 0.22)}px 60% 60%`,
      }
    }}>
      <Typography sx={{
        fontSize: size * 0.27, fontWeight: 900, color: C.pearl,
        letterSpacing: '-0.5px', zIndex: 1, fontFamily: '"Georgia", serif',
      }}>SW</Typography>
    </Box>
  );
}

export default function Layout() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const navigate  = useNavigate();
  const location  = useLocation();
  const { user, logout } = useAuth();
  const isMobile  = useMediaQuery('(max-width:600px)');

  const drawer = (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', background: C.sidebarGrad }}>
      {/* Brand */}
      <Box sx={{ p: 3, display: 'flex', alignItems: 'center', gap: 1.5 }}>
        <Logo size={42} />
        <Box>
          <Typography sx={{ fontWeight: 900, fontSize: '1.1rem', color: C.pearl, letterSpacing: '-0.3px', lineHeight: 1.1 }}>
            SW PG
          </Typography>
          <Typography sx={{ fontSize: '0.6rem', color: 'rgba(245,240,232,0.45)', letterSpacing: 2.5, textTransform: 'uppercase' }}>
            Personal OS
          </Typography>
        </Box>
      </Box>

      <Divider sx={{ borderColor: 'rgba(245,240,232,0.08)', mx: 2 }} />

      {/* Nav */}
      <List sx={{ px: 1.5, pt: 1.5, flex: 1 }}>
        {menuItems.map(item => {
          const active = location.pathname === item.path ||
            (item.path !== '/' && location.pathname.startsWith(item.path));
          return (
            <ListItem key={item.text} disablePadding sx={{ mb: 0.5 }}>
              <ListItemButton
                onClick={() => { navigate(item.path); if (isMobile) setMobileOpen(false); }}
                sx={{
                  borderRadius: 2, px: 2, py: 1,
                  bgcolor: active ? 'rgba(71,133,89,0.22)' : 'transparent',
                  border: `1px solid ${active ? 'rgba(71,133,89,0.45)' : 'transparent'}`,
                  '&:hover': { bgcolor: 'rgba(71,133,89,0.14)', border: '1px solid rgba(71,133,89,0.25)', transform: 'translateX(3px)' },
                  transition: 'all 0.18s ease',
                }}
              >
                <ListItemIcon sx={{ minWidth: 36, color: active ? C.greenLight : 'rgba(245,240,232,0.42)' }}>
                  {item.icon}
                </ListItemIcon>
                <ListItemText primary={item.text} primaryTypographyProps={{
                  fontWeight: active ? 700 : 500,
                  color: active ? C.pearl : 'rgba(245,240,232,0.58)',
                  fontSize: '0.875rem',
                }} />
                {active && <Box sx={{ width: 3, height: 18, borderRadius: 2, bgcolor: C.green }} />}
              </ListItemButton>
            </ListItem>
          );
        })}
      </List>

      <Divider sx={{ borderColor: 'rgba(245,240,232,0.08)', mx: 2 }} />
      <Box sx={{ p: 1.5 }}>
        <ListItemButton onClick={() => logout()} sx={{
          borderRadius: 2, px: 2, py: 1,
          '&:hover': { bgcolor: 'rgba(220,50,50,0.15)' }, transition: 'all 0.18s'
        }}>
          <ListItemIcon sx={{ minWidth: 36, color: 'rgba(245,240,232,0.3)' }}><LogoutIcon fontSize="small" /></ListItemIcon>
          <ListItemText primary="Logout" primaryTypographyProps={{ color: 'rgba(245,240,232,0.35)', fontSize: '0.85rem' }} />
        </ListItemButton>
      </Box>
    </Box>
  );

  const pageTitle = menuItems.find(m => m.path === location.pathname)?.text || 'Dashboard';

  return (
    <Box sx={{ display: 'flex', bgcolor: C.cream, minHeight: '100vh', position: 'relative' }}>
      <AnimatedBackground />
      <CursorGlow />

      {/* Top bar */}
      <AppBar position="fixed" elevation={0} sx={{
        zIndex: t => t.zIndex.drawer + 1,
        bgcolor: 'rgba(250,247,242,0.88)',
        backdropFilter: 'blur(14px)',
        WebkitBackdropFilter: 'blur(14px)',
        borderBottom: `1px solid ${C.cardBorder}`,
      }}>
        <Toolbar sx={{ gap: 2 }}>
          <IconButton edge="start" onClick={() => setMobileOpen(!mobileOpen)}
            sx={{ display: { sm: 'none' }, color: C.purple }}>
            <MenuIcon />
          </IconButton>
          <Box sx={{ display: { xs: 'flex', sm: 'none' }, alignItems: 'center', gap: 1 }}>
            <Logo size={30} />
          </Box>
          <Typography fontWeight={700} sx={{ flex: 1, color: C.purple, fontSize: '1rem' }}>
            {pageTitle}
          </Typography>
          <Box sx={{ px: 2, py: 0.6, borderRadius: 10,
            bgcolor: 'rgba(71,133,89,0.1)', border: `1px solid rgba(71,133,89,0.2)`,
            display: 'flex', alignItems: 'center', gap: 1 }}>
            <Box sx={{ width: 7, height: 7, borderRadius: '50%', bgcolor: C.green,
              boxShadow: `0 0 6px ${C.green}`, animation: 'pulse 2s ease infinite',
              '@keyframes pulse': { '0%,100%': { opacity: 1 }, '50%': { opacity: 0.5 } } }} />
            <Typography variant="caption" sx={{ color: C.green, fontWeight: 700 }}>
              {user?.username || 'Sirawdink'}
            </Typography>
          </Box>
        </Toolbar>
      </AppBar>

      {/* Sidebar */}
      <Box component="nav" sx={{ width: { sm: drawerWidth }, flexShrink: { sm: 0 }, zIndex: 1 }}>
        <Drawer
          variant={isMobile ? 'temporary' : 'permanent'}
          open={isMobile ? mobileOpen : true}
          onClose={() => setMobileOpen(false)}
          ModalProps={{ keepMounted: true }}
          sx={{ '& .MuiDrawer-paper': { width: drawerWidth, boxSizing: 'border-box', border: 'none', boxShadow: '4px 0 20px rgba(22,23,72,0.15)' } }}
        >
          {drawer}
        </Drawer>
      </Box>

      {/* Page content */}
      <Box component="main" sx={{
        flexGrow: 1, position: 'relative', zIndex: 1,
        width: { sm: `calc(100% - ${drawerWidth}px)` },
        minHeight: '100vh',
      }}>
        <Toolbar />
        <Box sx={{ p: { xs: 2, sm: 3 } }}>
          <Outlet />
        </Box>
      </Box>
    </Box>
  );
}
